(function($){
  const pluginName = 'jqSignature';
  function Signature(element, options){
    this.$el = $(element);
    this.settings = $.extend({ width: '100%', height: 220, lineWidth: 2, lineColor: '#111827', background: '#ffffff' }, options);
    this.canvas = document.createElement('canvas');
    this.ctx = this.canvas.getContext('2d');
    this.drawing = false;
    this.init();
  }
  Signature.prototype.init = function(){
    const self = this;
    this.$el.addClass('jq-signature').empty().append(this.canvas);
    this.resize();
    this.clearCanvas();
    const start = function(x, y){
      self.drawing = true;
      self.ctx.beginPath();
      self.ctx.moveTo(x, y);
    };
    const move = function(x, y){
      if(!self.drawing) return;
      self.ctx.lineTo(x, y);
      self.ctx.stroke();
      self.$el.trigger('jq.signature.changed');
    };
    const stop = function(){
      if(!self.drawing) return;
      self.ctx.closePath();
      self.drawing = false;
    };
    const getPos = (e) => {
      const rect = self.canvas.getBoundingClientRect();
      if(e.touches && e.touches.length){
        return { x: e.touches[0].clientX - rect.left, y: e.touches[0].clientY - rect.top };
      }
      return { x: e.clientX - rect.left, y: e.clientY - rect.top };
    };
    this.canvas.addEventListener('mousedown', function(e){ const p = getPos(e); start(p.x, p.y); });
    this.canvas.addEventListener('touchstart', function(e){ const p = getPos(e); start(p.x, p.y); e.preventDefault(); });
    window.addEventListener('mousemove', function(e){ const p = getPos(e); move(p.x, p.y); });
    window.addEventListener('touchmove', function(e){ const p = getPos(e); move(p.x, p.y); e.preventDefault(); });
    window.addEventListener('mouseup', stop);
    window.addEventListener('touchend', stop);
    window.addEventListener('resize', () => this.resize());
  };
  Signature.prototype.resize = function(){
    const width = typeof this.settings.width === 'number' ? this.settings.width : this.$el.width();
    this.canvas.width = width;
    this.canvas.height = this.settings.height;
    this.ctx.lineWidth = this.settings.lineWidth;
    this.ctx.lineCap = 'round';
    this.ctx.strokeStyle = this.settings.lineColor;
    this.ctx.fillStyle = this.settings.background;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
  };
  Signature.prototype.clearCanvas = function(){
    this.ctx.fillStyle = this.settings.background;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    this.$el.trigger('jq.signature.changed');
  };
  Signature.prototype.getDataURL = function(){
    return this.canvas.toDataURL('image/png');
  };
  Signature.prototype.importData = function(data){
    if(!data) return;
    const img = new Image();
    const ctx = this.ctx;
    const self = this;
    img.onload = function(){
      self.clearCanvas();
      ctx.drawImage(img, 0, 0);
    };
    img.src = data;
  };
  $.fn[pluginName] = function(option){
    const args = Array.prototype.slice.call(arguments, 1);
    let returnValue;
    this.each(function(){
      let instance = $.data(this, 'plugin_' + pluginName);
      if(!instance){
        if(typeof option === 'string') return;
        instance = new Signature(this, option);
        $.data(this, 'plugin_' + pluginName, instance);
      }
      if(typeof option === 'string' && typeof instance[option] === 'function'){
        const result = instance[option].apply(instance, args);
        if(result !== undefined){
          returnValue = result;
        }
      }
    });
    return returnValue !== undefined ? returnValue : this;
  };
})(jQuery);
